#include <iostream>
#include <cstring>
#include <cstdio>

void concatenateStrings(const char* s1, const char* s2) {
    char buffer[512];

    int i = 0;
    while (s1[i] != '\0') {
        buffer[i] = s1[i];
        i++;
    }

    int j = 0;
    while (s2[j] != '\0') {
        buffer[i + j] = s2[j];
        j++;
    }
    buffer[i + j] = '\0';

    printf("%s\n", buffer);
}

int main() {
    concatenateStrings("Hello", " World");
    concatenateStrings("", "World");
    concatenateStrings("Hello", "");
    concatenateStrings("", "");
    concatenateStrings("Programming is fun!", " Let's learn C++.");
    return 0;
}
